CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  user_role app_role := 'user';
BEGIN
  -- Check if this is an admin email
  IF NEW.email IN ('victor@7bee.com', 'andre@7bee.com') THEN
    user_role := 'admin';
  END IF;

  -- Insert profile without default unit
  INSERT INTO public.profiles (user_id, name)
  VALUES (
    NEW.id, 
    COALESCE(NEW.raw_user_meta_data->>'name', split_part(NEW.email, '@', 1))
  );

  -- Assign role
  INSERT INTO public.user_roles (user_id, role)
  VALUES (NEW.id, user_role);

  -- If admin, grant admin permission to all units
  IF user_role = 'admin' THEN
    INSERT INTO public.user_unit_permissions (user_id, unit_id, permission)
    SELECT NEW.id, u.id, 'admin'::permission_type
    FROM public.units u;
  END IF;

  RETURN NEW;
END;
$function$
